import React from 'https://cdn.jsdelivr.net/npm/react@17.0.2/+esm';
import ReactDOM from 'https://cdn.jsdelivr.net/npm/react-dom@17.0.2/+esm';
import { Button, Container } from 'https://cdn.jsdelivr.net/npm/@material-ui/core@4.12.4/+esm';

const MyCustomComponent = ({ data, updateData, runQuery }) => (
  <Container>
    <h1>{data.title}</h1>
    <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
      {(data.buttons || []).map((btn, i) => (
        <Button
          key={i}
          color={btn.color || 'primary'}
          variant={btn.variant || 'outlined'}
          onClick={() => btn.queryName && runQuery(btn.queryName)}
        >
          {btn.label}
        </Button>
      ))}
    </div>
  </Container>
);

const ConnectedComponent = Tooljet.connectComponent(MyCustomComponent);
ReactDOM.render(<ConnectedComponent />, document.body);
